#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int x, y, z;
        if (scanf("%d %d %d", &x, &y, &z) != 3) break;
        int total = x + y;
        int ans = (total >= z) ? 0 : (z - total);
        printf("%d\n", ans);
    }
    return 0;
}

